// ZMK Studio apply script for evolved V2 layout
window.CHARYBDIS_VERSION = "evolved-v2";

window.CHARYBDIS_FINAL_LAYOUT = [];
window._CHARYBDIS_APPLY_ERRORS = [];

function clickKeyButton(layer, x, y) {
  const btn = document.querySelector(`[data-layer='${layer}'][data-x='${x}'][data-y='${y}']`);
  if (btn) btn.click();
  return !!btn;
}

function selectBehavior(name) {
  const sel = document.querySelector('select.behavior-select');
  if (!sel) return false;
  for (let i = 0; i < sel.options.length; i++) {
    if (sel.options[i].text.trim().toLowerCase() === name.toLowerCase()) {
      sel.selectedIndex = i;
      sel.dispatchEvent(new Event('change', {bubbles: true}));
      return true;
    }
  }
  return false;
}

function typeParameter(text) {
  const inp = document.querySelector('input.parameter-input, input[type=text].parameter');
  if (!inp) return false;
  inp.value = text;
  inp.dispatchEvent(new Event('input', {bubbles: true}));
  inp.dispatchEvent(new Event('change', {bubbles: true}));
  return true;
}

function addModifier(name) {
  const mods = document.querySelectorAll('.modifier-checkbox, .modifier-item');
  for (const el of mods) {
    if (el.textContent.trim().toLowerCase() === name.toLowerCase()) {
      if (!el.checked && el.click) el.click();
      return true;
    }
  }
  return false;
}

async function applyKey(layer, x, y, behavior, parameter, modifiers, label) {
  const ok = clickKeyButton(layer, x, y);
  if (!ok) {
    window._CHARYBDIS_APPLY_ERRORS.push({layer, x, y, label, error: 'key button not found'});
    return false;
  }
  await new Promise(r => setTimeout(r, 30));
  const bok = selectBehavior(behavior);
  if (!bok) {
    window._CHARYBDIS_APPLY_ERRORS.push({layer, x, y, label, error: 'behavior not found: ' + behavior});
    return false;
  }
  await new Promise(r => setTimeout(r, 30));
  if (parameter) {
    const pok = typeParameter(parameter);
    if (!pok) {
      window._CHARYBDIS_APPLY_ERRORS.push({layer, x, y, label, error: 'parameter failed: ' + parameter});
      return false;
    }
  }
  await new Promise(r => setTimeout(r, 30));
  for (const mod of (modifiers || [])) {
    addModifier(mod);
  }
  window.CHARYBDIS_FINAL_LAYOUT.push({layer, x, y, label, behavior, parameter, modifiers});
  return true;
}

